        employee_id: 1,
        leave_type: 'annual',
        start_date: new Date('2025-01-01'),
        end_date: new Date('2025-01-03'),
        reason: 'Vacation',
        status: 'draft',
        submitted_at: null,
        reviewed_by: null,
        reviewed_at: null,
        comments: null,
        manager_id: null,
        created_at: new Date(),
        updated_at: new Date(),
      };
      mockClient.query
        .mockResolvedValueOnce(undefined) // BEGIN
        .mockResolvedValueOnce({ rows: [fakeRow] }) // INSERT
        .mockResolvedValueOnce(undefined) // audit INSERT
        .mockResolvedValueOnce(undefined); // COMMIT

      const result = await repo.create(dto, 1);
      expect(result.id).toBe(10);
      expect(result.status).toBe('draft');
      expect(mockClient.query).toHaveBeenCalledWith('BEGIN');
      expect(mockClient.query).toHaveBeenCalledWith(
        expect.stringContaining('INSERT INTO leave_requests'),
        expect.any(Array)
      );
      expect(mockClient.query).toHaveBeenCalledWith(
        expect.stringContaining('INSERT INTO audit_log'),
        expect.any(Array)
      );
      expect(mockClient.query).toHaveBeenCalledWith('COMMIT');
      expect(mockClient.release).toHaveBeenCalled();
    });
  });

  describe('findById', () => {
    it('should return a leave request when found', async () => {
      const fakeRow = { id: 1, employee_id: 1, leave_type: 'sick', start_date: new Date(), end_date: new Date(), reason: 'Flu', status: 'draft', submitted_at: null, reviewed_by: null, reviewed_at: null, comments: null, manager_id: null, created_at: new Date(), updated_at: new Date() };
      (pool.query as jest.Mock).mockResolvedValueOnce({ rows: [fakeRow] });
      const result = await repo.findById(1);
      expect(result).not.toBeNull();
      expect(result!.id).toBe(1);
    });

    it('should return null when not found', async () => {
      (pool.query as jest.Mock).mockResolvedValueOnce({ rows: [] });
      const result = await repo.findById(999);
      expect(result).toBeNull();
    });
